import{c,a0 as a,U as r,j as u,g as o,n as t,o as i,m as d,h as p,aA as s,S as m}from"./chunks/framework.Dvkoa_vi.js";const A=JSON.parse('{"title":"Proyecto final del curso","description":"Aplicación de reservas construida en cuatro módulos progresivos (Tipo de recurso, Recurso, Horario, Reserva) que el alumno desarrolla a lo largo de las 22 sesiones.","frontmatter":{"title":"Proyecto final del curso","description":"Aplicación de reservas construida en cuatro módulos progresivos (Tipo de recurso, Recurso, Horario, Reserva) que el alumno desarrolla a lo largo de las 22 sesiones.","outline":"deep"},"headers":[],"relativePath":"06-proyecto-final/index.md","filePath":"06-proyecto-final/index.md"}'),g={name:"06-proyecto-final/index.md"};function b(h,e,v,f,R,C){const l=a("CopyOrDownloadAsMarkdownButtons"),n=a("Mermaid");return r(),u("div",null,[e[1]||(e[1]=o("div",{style:{display:"none"},hidden:"true","aria-hidden":"true"},"Are you an LLM? You can read better optimized documentation at /curso-normalizacion/06-proyecto-final.md for this page in Markdown format",-1)),e[2]||(e[2]=o("h1",{id:"proyecto-final-del-curso",tabindex:"-1"},[t("Proyecto final del curso "),o("a",{class:"header-anchor",href:"#proyecto-final-del-curso","aria-label":"Permalink to “Proyecto final del curso”"},"​")],-1)),i(l),e[3]||(e[3]=d('<nav class="table-of-contents"><ul><li><a href="#vision-global">Visión global</a></li><li><a href="#los-cuatro-modulos">Los cuatro módulos</a></li><li><a href="#reglas-de-git-y-entregas">Reglas de Git y entregas</a></li><li><a href="#hitos-por-sesion">Hitos por sesión</a></li><li><a href="#modulo-1-—-tipo-de-recurso">Módulo 1 — Tipo de recurso</a><ul><li><a href="#objetivos">Objetivos</a></li><li><a href="#como-se-aprende">Cómo se aprende</a></li><li><a href="#criterios-de-aceptacion">Criterios de aceptación</a></li></ul></li><li><a href="#modulo-2-—-recurso">Módulo 2 — Recurso</a><ul><li><a href="#objetivos-1">Objetivos</a></li><li><a href="#como-se-aprende-1">Cómo se aprende</a></li><li><a href="#criterios-de-aceptacion-1">Criterios de aceptación</a></li></ul></li><li><a href="#modulo-3-—-horario">Módulo 3 — Horario</a><ul><li><a href="#objetivos-2">Objetivos</a></li><li><a href="#como-se-aprende-2">Cómo se aprende</a></li><li><a href="#criterios-de-aceptacion-2">Criterios de aceptación</a></li></ul></li><li><a href="#modulo-4-—-reserva">Módulo 4 — Reserva</a><ul><li><a href="#objetivos-3">Objetivos</a></li><li><a href="#como-se-aprende-3">Cómo se aprende</a></li><li><a href="#criterios-de-aceptacion-3">Criterios de aceptación</a></li></ul></li><li><a href="#lista-de-control-final">Lista de control final</a></li><li><a href="#como-navegar-a-partir-de-aqui">Cómo navegar a partir de aquí</a></li></ul></nav><div class="info custom-block"><p class="custom-block-title">FILOSOFÍA</p><p>El proyecto final <strong>no es una entrega aislada</strong> al cierre del curso. Son <strong>cuatro módulos progresivos</strong> que el alumno va construyendo a lo largo de las sesiones. Cada sesión añade una pieza al módulo activo y, al final, los cuatro módulos componen una aplicación de reservas de tamaño real.</p><p>Cada día comienza con <strong>todo lo del día anterior resuelto en una rama nueva del Git</strong>: nadie se queda descolgado, y la solución del día anterior es siempre el punto de partida del siguiente.</p></div><h2 id="vision-global" tabindex="-1">Visión global <a class="header-anchor" href="#vision-global" aria-label="Permalink to “Visión global”">​</a></h2><p>La aplicación final permite a un usuario CAS:</p><ul><li>Consultar los <strong>tipos de recurso</strong> disponibles (aulas, salas, equipos…).</li><li>Consultar los <strong>recursos</strong> concretos (Aula 12, Sala A, Proyector…), filtrarlos y administrarlos según rol.</li><li>Definir el <strong>horario semanal</strong> de un recurso (apertura, cierre, bloqueos puntuales, franjas).</li><li>Crear, ver y cancelar <strong>reservas</strong> validadas contra disponibilidad, festivos y solapamientos.</li></ul>',5)),(r(),p(m,null,{default:s(()=>[i(n,{id:"mermaid-44",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20TR%5BTipo%20de%20Recurso%3Cbr%2F%3ECat%C3%A1logo%20simple%5D%20--%3E%7C1..N%7C%20RC%5BRecurso%3Cbr%2F%3EInstancia%20concreta%5D%0A%20%20%20%20RC%20--%3E%7C1..1%7C%20HR%5BHorario%20semanal%3Cbr%2F%3EFranjas%20%2B%20bloqueos%5D%0A%20%20%20%20RC%20--%3E%7C1..N%7C%20RS%5BReserva%3Cbr%2F%3ED%C3%ADa%2Fhora%2Fusuario%5D%0A%20%20%20%20HR%20-.-%3E%7C%22valida%22%7C%20RS%0A%20%20%20%20FES%5BFestivos%5D%20-.-%3E%7C%22bloquea%22%7C%20RS%0A%20%20%20%20style%20TR%20fill%3A%23e3f2fd%0A%20%20%20%20style%20RC%20fill%3A%23e8f5e9%0A%20%20%20%20style%20HR%20fill%3A%23fff3e0%0A%20%20%20%20style%20RS%20fill%3A%23fce4ec%0A"})]),fallback:s(()=>[...e[0]||(e[0]=[t(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=d('<h2 id="los-cuatro-modulos" tabindex="-1">Los cuatro módulos <a class="header-anchor" href="#los-cuatro-modulos" aria-label="Permalink to “Los cuatro módulos”">​</a></h2><table tabindex="0"><thead><tr><th>Módulo</th><th>Modo de aprendizaje</th><th>Sesión de cierre</th><th>Rama de Git</th></tr></thead><tbody><tr><td><strong>1. Tipo de recurso</strong></td><td><strong>Hilo conductor</strong> — el material de las sesiones lo construye contigo en clase.</td><td>Sesión 14</td><td><code>tiporecurso-&lt;nombre&gt;</code></td></tr><tr><td><strong>2. Recurso</strong></td><td><strong>Ejercicio guiado</strong> — repites el patrón sobre una entidad con auditoría y seguridad.</td><td>Sesión 14 / 16</td><td><code>recurso-&lt;nombre&gt;</code></td></tr><tr><td><strong>3. Horario</strong></td><td><strong>Ejercicio de profundización</strong> — primer caso con objetos complejos y estado compartido.</td><td>Sesión 17</td><td><code>horario-&lt;nombre&gt;</code></td></tr><tr><td><strong>4. Reserva</strong></td><td><strong>Cierre integrador</strong> — combina todo y aplica las sesiones avanzadas.</td><td>Sesión 22</td><td><code>reserva-&lt;nombre&gt;</code></td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">CÓMO LO VAS A VIVIR</p><ul><li>En el <strong>Módulo 1</strong> el material te lleva de la mano: la sesión explica y muestra; tú reproduces el mismo patrón en tu rama. Es <strong>rodaje</strong>.</li><li>En el <strong>Módulo 2</strong> ya tienes el patrón. La sesión añade pequeñas piezas (auditoría, idioma, permisos) y tú las aplicas. Es <strong>consolidación</strong>.</li><li>En los <strong>Módulos 3 y 4</strong> ya eres autónomo. La sesión añade conceptos avanzados (Pinia, validaciones cruzadas, router avanzado, roles) y tú decides cómo integrarlos. Es <strong>proyecto</strong>.</li></ul></div><h2 id="reglas-de-git-y-entregas" tabindex="-1">Reglas de Git y entregas <a class="header-anchor" href="#reglas-de-git-y-entregas" aria-label="Permalink to “Reglas de Git y entregas”">​</a></h2><ul><li><strong>Una rama por módulo</strong>, con el nombre indicado en la tabla anterior.</li><li><strong>Cada día se publica en <code>master</code> la solución del día anterior</strong> del curso. El alumno hace <code>git pull</code> y, si quiere, rebasea su rama sobre la nueva base. Si se ha quedado atrás, <strong>descarta su trabajo del día anterior y arranca con la solución oficial</strong>.</li><li><strong>Commits frecuentes</strong>, pequeños y con mensaje en español. Que el historial cuente la historia.</li><li><strong>Tests siempre que el material los explique</strong> (sesión 18 introduce xUnit + <code>WebApplicationFactory</code>).</li><li><strong>Accesibilidad obligatoria</strong> en cada componente nuevo (sesión 21).</li></ul><div class="warning custom-block"><p class="custom-block-title">POR QUÉ DESCARTAR Y NO INTENTAR ARREGLAR</p><p>Si te has quedado descolgado un día, <strong>no inviertas la primera hora del día siguiente</strong> en rescatar tu rama: descarta y arranca con la solución oficial. El objetivo de cada sesión es <strong>aprender el siguiente concepto</strong>, no debuggear el del día anterior. Tendrás otra ocasión de aplicarlo en el siguiente módulo.</p></div><h2 id="hitos-por-sesion" tabindex="-1">Hitos por sesión <a class="header-anchor" href="#hitos-por-sesion" aria-label="Permalink to “Hitos por sesión”">​</a></h2><p>Esta es la tabla maestra que conviene revisar al inicio del curso. Indica <strong>qué del proyecto final</strong> trabaja cada sesión.</p><table tabindex="0"><thead><tr><th>#</th><th>Sesión</th><th>Módulo</th><th>Qué añades al proyecto</th></tr></thead><tbody><tr><td>1-2</td><td>Oracle · Fundamentos + ejercicio</td><td>1</td><td>Inspección del schema y tabla <code>TIPO_RECURSO</code> con <code>IDENTITY</code>, multiidioma y <code>CHECK</code></td></tr><tr><td>3-4</td><td>Oracle · Tablas y vistas + ejercicio</td><td>1</td><td>Vista <code>VRES_TIPO_RECURSO</code> con alias para automapeo</td></tr><tr><td>5</td><td>Oracle · Paquetes CRUD</td><td>1 + 3</td><td><code>PKG_RES_TIPO_RECURSO</code> (<code>LISTAR / OBTENER / CREAR / ACTUALIZAR / ELIMINAR</code>) <strong>+</strong> primer contacto con arrays de objetos para el módulo Horario</td></tr><tr><td>6</td><td>.NET · Introducción</td><td>—</td><td>Setup del proyecto en tu rama</td></tr><tr><td>7</td><td>.NET · DTOs y APIs</td><td>1</td><td>DTOs (<code>TipoRecursoLectura / CrearDto / ActualizarDto</code>) + controller con CRUD en memoria</td></tr><tr><td>8</td><td>.NET · Servicios Oracle</td><td>1 + 2 (auditoría)</td><td>Servicio real con <code>ClaseOracleBD3</code> + introducción de campos de auditoría para el módulo Recurso</td></tr><tr><td>9</td><td>.NET · Validación y errores</td><td>1 + 3 (conflictos)</td><td>DataAnnotations en los DTOs + plantilla de validación cruzada para horarios</td></tr><tr><td>10</td><td>.NET · DataTable + ClaseCrud</td><td>1 + 2 (filtros)</td><td>Paginación, orden, filtros server-side de <code>TipoRecurso</code> + extensión para <code>Recurso</code> con campos extra</td></tr><tr><td>11</td><td>.NET · OpenAPI y Scalar</td><td>1</td><td>XML doc + Scalar pulido en tu rama</td></tr><tr><td>12</td><td>Vue · Fundamentos</td><td>1</td><td>Estructura del cliente, primera vista de <code>TipoRecurso</code></td></tr><tr><td>13</td><td>Vue · Directivas y eventos</td><td>1</td><td>Tabla y filtro de <code>TipoRecurso</code></td></tr><tr><td>14</td><td>Vue · Componentes y comunicación</td><td>1 + 3 (día) + 4 (Hora/Duración)</td><td>Modal de edición de <code>TipoRecurso</code> <strong>+</strong> componente <code>BloqueDia</code> para Horario y <code>SelectorHoraDuracion</code> para Reserva</td></tr><tr><td>15</td><td>Vue · Arquitectura: composables y servicios</td><td>1 + 2</td><td>Composable <code>useTipoRecurso</code> + plantilla del de <code>Recurso</code></td></tr><tr><td>16</td><td>Vue · Componentes internos UA</td><td>1</td><td>CRUD de <code>TipoRecurso</code> completo cliente (la integradora <code>Sesion10CrudRecursos</code> es la referencia visual)</td></tr><tr><td>17</td><td>Integración · Llamadas a la API y autenticación</td><td>1 + 2 (idioma+codper)</td><td>Sustituir el mock por <code>useAxios</code>, lectura de claims y filtrado de listas por idioma del usuario</td></tr><tr><td>18</td><td>Integración · Validación en todas las capas</td><td>1 + 3 (conflictos)</td><td><code>useGestionFormularios</code> aplicado al formulario de <code>TipoRecurso</code> + validador cruzado de Horario</td></tr><tr><td>19</td><td>Integración · Gestión de errores</td><td>1 + 2</td><td>Toast + confirmación en eliminación de <code>TipoRecurso</code> y <code>Recurso</code>, errores Oracle traducidos</td></tr><tr><td>20</td><td>Integración · DataTable</td><td>1 + 2 (cierre) + 4 (lógica)</td><td>Cierre del módulo 2: DataTable de <code>Recurso</code> con acciones por fila y filtro desplegable por tipo <strong>+</strong> primer endpoint de &quot;disponibilidad&quot; para Reserva</td></tr><tr><td>21</td><td>Avanzadas · i18n</td><td>1-4</td><td>Traducciones de los formularios a <code>es / ca / en</code></td></tr><tr><td>22</td><td>Avanzadas · Seguridad (roles, políticas)</td><td>2 + 4</td><td><code>[Authorize(Roles)]</code> en las APIs y <code>meta.roles</code> en el router para <code>Recurso</code> y <code>Reserva</code></td></tr><tr><td>23</td><td>Avanzadas · Pinia</td><td>3 + 4</td><td>Estado compartido del horario en edición y filtros del calendario de reserva</td></tr><tr><td>24</td><td>Avanzadas · Tests</td><td>1-4</td><td>xUnit + <code>WebApplicationFactory</code> sobre tus controladores</td></tr><tr><td>25</td><td>Avanzadas · Ficheros</td><td>4</td><td>Adjuntar justificante a una reserva (opcional)</td></tr><tr><td>26</td><td>Avanzadas · Serilog</td><td>1-4</td><td>Sinks Console / Oracle / File / Email en tu proyecto</td></tr><tr><td>27</td><td>Avanzadas · Accesibilidad y ENS</td><td>1-4</td><td>Auditoría WCAG de tus formularios y tablas</td></tr><tr><td>28</td><td>Avanzadas · Copilot</td><td>1-4</td><td>Productividad sobre el proyecto ya construido</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">CÓMO LEER LA TABLA</p><ul><li>&quot;Módulo&quot; indica <strong>a qué módulo aporta</strong> el trabajo de esa sesión.</li><li>&quot;Qué añades&quot; es el <strong>delta mínimo</strong> esperado al cierre. Puedes ir más lejos.</li><li>Si un alumno se centra en seguir el material en clase, al terminar la sesión 14 tiene el <strong>Módulo 1 cerrado</strong>. Las sesiones 11 a 14 lo extienden con seguridad e integración real.</li></ul></div><h2 id="modulo-1-—-tipo-de-recurso" tabindex="-1">Módulo 1 — Tipo de recurso <a class="header-anchor" href="#modulo-1-—-tipo-de-recurso" aria-label="Permalink to “Módulo 1 — Tipo de recurso”">​</a></h2><h3 id="objetivos" tabindex="-1">Objetivos <a class="header-anchor" href="#objetivos" aria-label="Permalink to “Objetivos”">​</a></h3><ul><li><strong>Oracle</strong>: tabla, vista y paquete básico (<code>IDENTITY</code>, multiidioma, <code>CHECK</code>, grants <code>WEB</code>).</li><li><strong>.NET</strong>: API CRUD completa con filtros, ordenación, validación y seguridad básica (<code>[Authorize]</code>).</li><li><strong>Vue</strong>: DataTable, modales, formularios con validación HTML y errores del servidor.</li><li><strong>Accesibilidad</strong>: tabla y formulario WCAG-AA (labels asociadas, focus visible, mensajes con <code>role=&quot;alert&quot;</code>).</li><li><strong>GIT</strong>: rama <code>tiporecurso-&lt;nombre&gt;</code> por alumno.</li></ul><h3 id="como-se-aprende" tabindex="-1">Cómo se aprende <a class="header-anchor" href="#como-se-aprende" aria-label="Permalink to “Cómo se aprende”">​</a></h3><p>El material <strong>construye este módulo contigo en clase</strong> sesión a sesión. Tu trabajo es <strong>reproducir el mismo patrón en tu rama</strong>, no descubrirlo de cero. Al cierre de la sesión 14 deberías tener:</p><ul><li>Tabla <code>TIPO_RECURSO</code>, vista <code>VRES_TIPO_RECURSO</code>, paquete <code>PKG_RES_TIPO_RECURSO</code>.</li><li>Endpoints <code>GET / GET {id} / POST / PUT / DELETE /api/TipoRecursos</code>.</li><li>Vista Vue con DataTable, modal de alta y modal de edición.</li><li>Eliminación protegida con <code>PopUpModal</code> y toast de confirmación.</li><li>Errores Oracle traducidos vía <code>Resources/SharedResource.{es,ca,en}.resx</code>.</li></ul><h3 id="criterios-de-aceptacion" tabindex="-1">Criterios de aceptación <a class="header-anchor" href="#criterios-de-aceptacion" aria-label="Permalink to “Criterios de aceptación”">​</a></h3><ul><li>Crear, editar y eliminar un <code>TipoRecurso</code> desde la UI sin recargar la página.</li><li>Probar a eliminar un <code>TipoRecurso</code> con recursos asociados → debe mostrar <strong>banner global</strong> con mensaje localizado (<code>ORA-20703</code>).</li><li>Probar a obtener un <code>TipoRecurso</code> inexistente → debe mostrar <strong>toast</strong> rojo (<code>ORA-20702</code>).</li><li>El formulario debe ser accesible al teclado y leerse correctamente con lector de pantalla.</li></ul><h2 id="modulo-2-—-recurso" tabindex="-1">Módulo 2 — Recurso <a class="header-anchor" href="#modulo-2-—-recurso" aria-label="Permalink to “Módulo 2 — Recurso”">​</a></h2><h3 id="objetivos-1" tabindex="-1">Objetivos <a class="header-anchor" href="#objetivos-1" aria-label="Permalink to “Objetivos”">​</a></h3><ul><li><strong>Oracle</strong>: tabla <code>RECURSO</code> con campos de auditoría (<code>FECHA_CREACION</code>, <code>CODPER_CREADOR</code>), vista <code>VRES_RECURSO</code> optimizada por idioma y paquete extendido con operaciones de <strong>cambio de estado</strong> (activar / desactivar / marcar mantenimiento).</li><li><strong>.NET</strong>: lectura de <code>CodPer</code> e <code>Idioma</code> desde el JWT (<code>ControladorBase</code>), optimización de consultas a una sola columna idiomática, roles y permisos (el creador es propietario).</li><li><strong>Vue</strong>: DataTable con acciones extra (checks de estado), botones que abren otras vistas (calendario), captura y presentación de errores, desplegable filtrado por <code>TipoRecurso</code>.</li><li><strong>Accesibilidad</strong>: igual que el módulo 1, más anuncios <code>aria-live</code> para los toasts.</li><li><strong>GIT</strong>: rama <code>recurso-&lt;nombre&gt;</code>.</li></ul><h3 id="como-se-aprende-1" tabindex="-1">Cómo se aprende <a class="header-anchor" href="#como-se-aprende-1" aria-label="Permalink to “Cómo se aprende”">​</a></h3><p>El material te enseña los conceptos en sesiones puntuales (auditoría en .NET sesión 2, idioma/codper en sesión 11, permisos en sesión 16, filtros en sesión 14). El <strong>ejercicio del proyecto</strong> es aplicarlos a <code>Recurso</code> <strong>siguiendo el patrón</strong> del módulo 1.</p><h3 id="criterios-de-aceptacion-1" tabindex="-1">Criterios de aceptación <a class="header-anchor" href="#criterios-de-aceptacion-1" aria-label="Permalink to “Criterios de aceptación”">​</a></h3><ul><li>Solo el creador (o un rol administrador) puede modificar o eliminar un recurso.</li><li>Listado filtrado por tipo desde un desplegable accesible.</li><li>Cambio de estado del recurso (<code>Activo</code> ↔ <code>Mantenimiento</code>) con confirmación y toast.</li><li>Audit fields visibles en el detalle (fecha de creación y creador).</li></ul><h2 id="modulo-3-—-horario" tabindex="-1">Módulo 3 — Horario <a class="header-anchor" href="#modulo-3-—-horario" aria-label="Permalink to “Módulo 3 — Horario”">​</a></h2><h3 id="objetivos-2" tabindex="-1">Objetivos <a class="header-anchor" href="#objetivos-2" aria-label="Permalink to “Objetivos”">​</a></h3><ul><li><strong>Oracle</strong>: trabajo con arrays de objetos (<code>TYPE</code> colección) y validación de conflictos (franjas superpuestas) dentro del paquete.</li><li><strong>.NET</strong>: API que acepta objetos complejos, <strong>acciones fuera del CRUD</strong> (<code>copiar-a-toda-la-semana</code>, <code>bloquear-dia</code>), validación cruzada con FluentValidation.</li><li><strong>Vue</strong>: componente <code>BloqueDia</code> reutilizable por cada día de la semana, posibilidad de añadir / borrar varias franjas por día, <strong>bloquear día</strong> completo, <strong>copiar un día a toda la semana</strong>. Estado compartido del horario en edición con Pinia.</li><li><strong>GIT</strong>: rama <code>horario-&lt;nombre&gt;</code>.</li></ul><h3 id="como-se-aprende-2" tabindex="-1">Cómo se aprende <a class="header-anchor" href="#como-se-aprende-2" aria-label="Permalink to “Cómo se aprende”">​</a></h3><p>Este módulo presenta <strong>el primer caso real de un objeto complejo</strong> que no es un simple CRUD. La sesión 5 (Oracle) introduce el array; las sesiones 8 (Vue) y 17 (Pinia) dan las piezas de cliente; la 12 cierra la validación cruzada de conflictos. El <strong>ejercicio</strong> es ensamblarlo en una pantalla de edición.</p><h3 id="criterios-de-aceptacion-2" tabindex="-1">Criterios de aceptación <a class="header-anchor" href="#criterios-de-aceptacion-2" aria-label="Permalink to “Criterios de aceptación”">​</a></h3><ul><li>En la edición de un horario semanal el usuario puede añadir y eliminar franjas por día.</li><li>Bloquear un día entero con un solo gesto.</li><li>Copiar las franjas de un día a toda la semana con un botón.</li><li>Al guardar, si dos franjas del mismo día se solapan, el servidor responde 400 con <code>errors[&quot;&quot;]</code> describiendo el conflicto, y el banner global lo muestra en el idioma del usuario.</li></ul><h2 id="modulo-4-—-reserva" tabindex="-1">Módulo 4 — Reserva <a class="header-anchor" href="#modulo-4-—-reserva" aria-label="Permalink to “Módulo 4 — Reserva”">​</a></h2><h3 id="objetivos-3" tabindex="-1">Objetivos <a class="header-anchor" href="#objetivos-3" aria-label="Permalink to “Objetivos”">​</a></h3><ul><li><strong>Oracle</strong>: validación de la reserva contra horario, días festivos y solapamiento con otras reservas. Tabla <code>FESTIVO</code> con la lógica de tiempo.</li><li><strong>.NET</strong>: lógica de <strong>reservas disponibles vs bloqueadas</strong>, endpoint <code>/api/Reservas/disponibilidad?recursoId=…&amp;fecha=…</code>, validación de todo lo que llega.</li><li><strong>Vue</strong>: componentes <code>SelectorHora</code> y <code>SelectorDuracion</code> reutilizables, refresco automático al cambiar la fecha, opción de <strong>ver siguiente disponible</strong> si la fecha elegida está bloqueada, filtro avanzado por tipo de recurso con uso intensivo de <code>router.js</code> (query params + scroll restoration).</li><li><strong>Seguridad</strong>: solo usuarios con rol <code>RESERVAS</code> pueden crear; los propios usuarios pueden cancelar sus reservas.</li><li><strong>GIT</strong>: rama <code>reserva-&lt;nombre&gt;</code>.</li></ul><h3 id="como-se-aprende-3" tabindex="-1">Cómo se aprende <a class="header-anchor" href="#como-se-aprende-3" aria-label="Permalink to “Cómo se aprende”">​</a></h3><p>Es el módulo <strong>integrador</strong>. Reutiliza todo lo construido en los módulos 1-3 y aplica las sesiones avanzadas (seguridad, Pinia, tests, accesibilidad). Conviene <strong>cerrarlo en parejas o tríos</strong>: el código compartido y las decisiones de UX se benefician de la discusión.</p><h3 id="criterios-de-aceptacion-3" tabindex="-1">Criterios de aceptación <a class="header-anchor" href="#criterios-de-aceptacion-3" aria-label="Permalink to “Criterios de aceptación”">​</a></h3><ul><li>Crear una reserva válida: la disponibilidad se actualiza en vivo en la UI.</li><li>Intentar crear una reserva con solapamiento: el servidor responde 400 con mensaje localizado y se ve en el banner global.</li><li>Intentar crear una reserva en festivo: idem.</li><li>Cancelar una reserva propia desde la lista: confirmación con <code>PopUpModal</code> y toast de éxito.</li><li>Acceder sin rol <code>RESERVAS</code> a la pantalla de creación → redirección a <code>ExternalLoginFailure</code>.</li></ul><h2 id="lista-de-control-final" tabindex="-1">Lista de control final <a class="header-anchor" href="#lista-de-control-final" aria-label="Permalink to “Lista de control final”">​</a></h2><p>Antes de la entrega, repasa este checklist por módulo:</p><ul><li>[ ] <strong>Git</strong>: una rama por módulo, historial limpio, commits en español.</li><li>[ ] <strong>Oracle</strong>: tabla con <code>CHECK</code>, vista con alias para automapeo, paquete con <code>P_CODIGO_ERROR</code> / <code>P_MENSAJE_ERROR</code>.</li><li>[ ] <strong>.NET</strong>: DTOs con DataAnnotations, servicio con <code>Result&lt;T&gt;</code>, controladores que solo hacen <code>HandleResult(...)</code>.</li><li>[ ] <strong>Mensajes Oracle</strong>: usar <code># Resources.SharedResource.CLAVE|args #</code> para que viajen localizados.</li><li>[ ] <strong>Vue</strong>: vistas con <code>useGestionFormularios({ aislado: true })</code>, banner global + errores por campo, toasts en éxitos y errores reales.</li><li>[ ] <strong>Confirmación</strong>: <code>PopUpModal</code> antes de cualquier eliminación.</li><li>[ ] <strong>Seguridad</strong>: <code>[Authorize(Roles)]</code> donde proceda en API, <code>meta.roles</code> en las rutas Vue.</li><li>[ ] <strong>Accesibilidad</strong>: cada formulario y tabla pasa la auditoría WCAG-AA (sesión 21).</li><li>[ ] <strong>Tests</strong>: al menos un test por endpoint nuevo (sesión 18).</li><li>[ ] <strong>Serilog</strong>: la app emite eventos estructurados con <code>Code</code> y <code>RequestPath</code> (sesión 20).</li></ul><h2 id="como-navegar-a-partir-de-aqui" tabindex="-1">Cómo navegar a partir de aquí <a class="header-anchor" href="#como-navegar-a-partir-de-aqui" aria-label="Permalink to “Cómo navegar a partir de aquí”">​</a></h2><ul><li>Si estás empezando un módulo, lee primero la fila correspondiente en la <strong>tabla de hitos</strong> y abre las sesiones citadas.</li><li>Si te has quedado descolgado, descarta tu rama y arranca con la solución oficial del día anterior (es lo que recomienda el equipo).</li><li>Si tienes una duda concreta sobre <strong>dónde</strong> aplicar algo, busca en el sandbox: la demo equivalente está en <code>ClientApp/src/views/sesiones-vue/sesion-N/</code>.</li></ul>',44))])}const E=c(g,[["render",b]]);export{A as __pageData,E as default};
